import React from 'react';
import logo from './logo.svg';
import './App.css';

interface Music {
  name : string;
  artist : string;
  playcount : number;
}

interface TopTracks {
  tracks : Array<Music>;
}

const fetchTopTracks = async () : Promise <Array<Music> | string> => {
  const api = 'http://ws.audioscrobbler.com/2.0/?method=user.gettoptracks&user=gfxnx&api_key=c9d3233f3430ee28ba0e643cb973eac5&format=json'
  try {
    const response = await fetch(api); 
    if(!response.ok){
      throw new Error(`API call error : ${response.status}`)
    }
    const {data} = await response.json();
    return data;
  } catch (error) {
    return error.message; 
  }
}

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
          Edit <code>src/App.tsx</code> and save to reload.
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
    </div>
  );
}

export default App;
